import { describe, expect, it, vi } from 'vitest';
import {
  applyPhysicsMessage,
  type GraphViewPhysicsMessageHandlers,
} from '../../../../../src/extension/graphView/webview/messages/physics';

function createHandlers(
  overrides: Partial<GraphViewPhysicsMessageHandlers> = {},
): GraphViewPhysicsMessageHandlers {
  return {
    sendPhysicsSettings: vi.fn(),
    updatePhysicsSetting: vi.fn(() => Promise.resolve()),
    resetPhysicsSettings: vi.fn(() => Promise.resolve()),
    ...overrides,
  };
}

describe('graph view physics message', () => {
  it('sends current physics settings on request', async () => {
    const handlers = createHandlers();

    await expect(applyPhysicsMessage({ type: 'GET_PHYSICS_SETTINGS' }, handlers)).resolves.toBe(
      true,
    );

    expect(handlers.sendPhysicsSettings).toHaveBeenCalledOnce();
  });

  it('updates a single physics setting', async () => {
    const handlers = createHandlers();

    await expect(
      applyPhysicsMessage(
        {
          type: 'UPDATE_PHYSICS_SETTING',
          payload: { key: 'repelForce', value: 12 },
        },
        handlers,
      ),
    ).resolves.toBe(true);

    expect(handlers.updatePhysicsSetting).toHaveBeenCalledWith('repelForce', 12);
  });

  it('resets physics settings to defaults', async () => {
    const handlers = createHandlers();

    await expect(applyPhysicsMessage({ type: 'RESET_PHYSICS_SETTINGS' }, handlers)).resolves.toBe(
      true,
    );

    expect(handlers.resetPhysicsSettings).toHaveBeenCalledOnce();
  });

  it('returns false for unrelated messages', async () => {
    const handlers = createHandlers();

    await expect(
      applyPhysicsMessage(
        { type: 'UPDATE_FILTER_PATTERNS', payload: { patterns: ['dist/**'] } },
        handlers,
      ),
    ).resolves.toBe(false);
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  resetGraphViewPhysicsSettings,
  updateGraphViewPhysicsSetting,
} from '../../../../../src/extension/graphView/settings/physics/updates';

describe('graph view physics update helpers', () => {
  it('updates a single physics setting in repo-local settings', async () => {
    const update = vi.fn(() => Promise.resolve());

    await updateGraphViewPhysicsSetting('repelForce', 25, {
      getConfiguration: () => ({ update }),
    });

    expect(update).toHaveBeenCalledWith('physics.repelForce', 25);
  });

  it('updates a single physics setting at the requested configuration target', async () => {
    const update = vi.fn(() => Promise.resolve());

    await updateGraphViewPhysicsSetting('damping', 0.35, {
      getConfiguration: () => ({ update }),
      getConfigTarget: () => 'workspace-folder-target',
    });

    expect(update).toHaveBeenCalledWith('physics.damping', 0.35, 'workspace-folder-target');
  });

  it('resets every persisted physics setting back to the config default', async () => {
    const update = vi.fn(() => Promise.resolve());

    await resetGraphViewPhysicsSettings({
      getConfiguration: () => ({ update }),
    });

    expect(update.mock.calls).toEqual([
      ['physics.repelForce', undefined],
      ['physics.linkDistance', undefined],
      ['physics.linkForce', undefined],
      ['physics.damping', undefined],
      ['physics.centerForce', undefined],
    ]);
  });

  it('resets every persisted physics setting at the requested configuration target', async () => {
    const update = vi.fn(() => Promise.resolve());

    await resetGraphViewPhysicsSettings({
      getConfiguration: () => ({ update }),
      getConfigTarget: () => 'workspace-folder-target',
    });

    expect(update.mock.calls).toEqual([
      ['physics.repelForce', undefined, 'workspace-folder-target'],
      ['physics.linkDistance', undefined, 'workspace-folder-target'],
      ['physics.linkForce', undefined, 'workspace-folder-target'],
      ['physics.damping', undefined, 'workspace-folder-target'],
      ['physics.centerForce', undefined, 'workspace-folder-target'],
    ]);
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';

const mocks = vi.hoisted(() => {
  const configuration = { get: vi.fn((_: string, fallback: unknown) => fallback) };

  return {
    configuration,
    readPhysicsSettings: vi.fn(() => ({ damping: 0.6 })),
    updatePhysicsSetting: vi.fn(async () => undefined),
    resetPhysicsSettings: vi.fn(async () => undefined),
    getCodeGraphyConfiguration: vi.fn(() => configuration),
  };
});

vi.mock('vscode', () => ({
  workspace: {},
}));

vi.mock('../../../../src/extension/graphView/settings/physics/reader', () => ({
  readGraphViewPhysicsSettings: mocks.readPhysicsSettings,
}));

vi.mock('../../../../src/extension/repoSettings/current', () => ({
  getCodeGraphyConfiguration: mocks.getCodeGraphyConfiguration,
}));

vi.mock('../../../../src/extension/graphView/settings/physics/updates', () => ({
  updateGraphViewPhysicsSetting: mocks.updatePhysicsSetting,
  resetGraphViewPhysicsSettings: mocks.resetPhysicsSettings,
}));

import { createGraphViewProviderPhysicsSettingsMethods } from '../../../../src/extension/graphView/provider/physicsSettings';

describe('graphView/provider/physicsSettings default dependencies', () => {
  beforeEach(() => {
    mocks.getCodeGraphyConfiguration.mockClear();
    mocks.configuration.get.mockClear();
    mocks.readPhysicsSettings.mockClear();
    mocks.updatePhysicsSetting.mockClear();
    mocks.resetPhysicsSettings.mockClear();
  });

  it('reads and sends physics settings through the default vscode configuration bridge', () => {
    const source = { _sendMessage: vi.fn() };
    const methods = createGraphViewProviderPhysicsSettingsMethods(source as never);

    expect(methods._getPhysicsSettings()).toEqual({ damping: 0.6 });
    methods._sendPhysicsSettings();

    expect(mocks.getCodeGraphyConfiguration).toHaveBeenCalledTimes(2);
    expect(mocks.readPhysicsSettings).toHaveBeenNthCalledWith(
      1,
      mocks.configuration,
      {
        repelForce: 10,
        linkDistance: 80,
        linkForce: 0.15,
        damping: 0.7,
        centerForce: 0.1,
      },
    );
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'PHYSICS_SETTINGS_UPDATED',
      payload: { damping: 0.6 },
    });
  });

  it('updates physics settings through the default repo-local settings helpers', async () => {
    const methods = createGraphViewProviderPhysicsSettingsMethods({ _sendMessage: vi.fn() } as never);

    await methods._updatePhysicsSetting('damping', 0.25);

    expect(mocks.updatePhysicsSetting).toHaveBeenCalledOnce();
    const options = mocks.updatePhysicsSetting.mock.calls[0] as unknown as [
      unknown,
      unknown,
      {
        getConfiguration(): unknown;
      },
    ];
    expect(options[2].getConfiguration()).toBe(mocks.configuration);
    expect(mocks.getCodeGraphyConfiguration).toHaveBeenCalledOnce();
  });

  it('resets physics settings through the default repo-local settings helpers', async () => {
    const methods = createGraphViewProviderPhysicsSettingsMethods({ _sendMessage: vi.fn() } as never);

    await methods._resetPhysicsSettings();

    expect(mocks.resetPhysicsSettings).toHaveBeenCalledOnce();
    const options = mocks.resetPhysicsSettings.mock.calls[0] as unknown as [
      {
        getConfiguration(): unknown;
      },
    ];
    expect(options[0].getConfiguration()).toBe(mocks.configuration);
    expect(mocks.getCodeGraphyConfiguration).toHaveBeenCalledOnce();
  });
});

